1	// StateDrain is the dual of ResumeDriver: halt the hart via the Debug Module,
2	// read x1..x31 + DPC via Abstract Commands, populate hybrid_state_v1.
3	//
4	// Reuses ResumeDriver's DM register constants and DmiBus interface. Vector
5	// regs, FPRs, and CSRs beyond DPC are deferred to Phase 5.
6	
7	#pragma once
8	
9	#include "hybrid/abstract_command.hpp"
10	#include "hybrid/resume_driver.hpp"
11	#include "hybrid/state_abi.h"
12	
13	#include <cstdint>
14	#include <stdexcept>
15	
16	namespace hybrid
17	{
18	
19	class StateDrain
20	{
21	public:
22	  using RD = ResumeDriver;
23	
24	  explicit StateDrain(DmiBus& bus)
25	      : bus_{bus}
26	  {}
27	
28	  auto drain() -> hybrid_state_v1
29	  {
30	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
31	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
32	    poll_until_set(RD::kDmstatus, RD::kDmstatusAllhalted);
33	
34	    hybrid_state_v1 state{};
35	    state.magic   = HYBRID_STATE_MAGIC;
36	    state.version = HYBRID_STATE_VERSION;
37	    state.flags   = HYBRID_FLAG_RV64;
38	    state.priv    = 3;
39	
40	    for (uint16_t i = 1; i < 32; ++i)
41	      state.gpr[i] = read_64bit_register(regno_gpr(i));
42	
43	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
44	    return state;
45	  }
46	
47	private:
48	  auto read_64bit_register(uint16_t regno) -> uint64_t
49	  {
50	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
51	                                                     /*write=*/false));
52	    poll_until_clear(RD::kAbstractcs, RD::kAbstractcsBusy);
53	    const uint64_t lo = bus_.read(RD::kData0);
54	    const uint64_t hi = bus_.read(RD::kData1);
55	    return lo | (hi << 32);
56	  }
57	
58	  void poll_until_set(uint8_t reg, uint32_t mask)
59	  {
60	    for (unsigned i = 0; i < RD::kPollIterations; ++i)
61	      if ((bus_.read(reg) & mask) == mask) return;
62	    throw std::runtime_error("StateDrain: poll_until_set timed out");
63	  }
64	
65	  void poll_until_clear(uint8_t reg, uint32_t mask)
66	  {
67	    for (unsigned i = 0; i < RD::kPollIterations; ++i)
68	      if ((bus_.read(reg) & mask) == 0) return;
69	    throw std::runtime_error("StateDrain: poll_until_clear timed out");
70	  }
71	
72	  DmiBus& bus_;
73	};
74	
75	}  // namespace hybrid
