262	  {
263	    switch (type) {
264	    case MEM_TYPE::ILM:
265	      if constexpr (requires { cpu.set_ilm({}); }) {
266	        read_binary_file(path, [this](const auto& data) { cpu.set_ilm(data); });
267	      } else {
268	        throw std::runtime_error(
269	          "CPU does not support ILM - cannot load ILM ROM image");
270	      }
271	      break;
272	
273	    case MEM_TYPE::DLM:
274	      if constexpr (requires { cpu.set_dlm({}); }) {
275	        read_binary_file(path, [this](const auto& data) { cpu.set_dlm(data); });
276	      } else {
