278	          "CPU does not support DLM - cannot load DLM ROM image");
279	      }
280	      break;
281	
282	    case MEM_TYPE::RAM:
283	      read_binary_file(path, [this](const auto& data) {
284	        if (data.size() > platform.main_memory.data.size())
285	          throw std::runtime_error("RAM image size exceeds main memory size");
286	        std::copy(data.begin(), data.end(), platform.main_memory.data.begin());
287	      });
288	      break;
289	
290	    default:
291	      throw std::runtime_error("Unknown memory type");
292	    }
