295	  void reset()
296	  {
297	    static constexpr int core_num = CPU::NDS_NHART;
298	    static constexpr int reset_val = (1 << core_num) - 1;
299	
300	    platform.resetn.write(0);
301	    auto saved = context_config;
302	    context_config = {};
303	    this->run(1);
304	    context_config = saved;
305	
306	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
307	      spdlog::info("hart {} reset vector: {:#x}", i,
308	                   (uint64_t) platform.reset_vector[i].read());
309	
310	    platform.resetn.write(reset_val);
311	
312	    if (context_config.continue_from)
313	      restore_context(context_config.dir);
314	  }
315	
316	  int run(const uint64_t max_cycles = std::numeric_limits<uint64_t>::max())
317	  {
318	    auto sa = memzeroed<struct sigaction>();
319	    sa.sa_handler = sigint_handler;
320	    sigemptyset(&sa.sa_mask);
321	
322	    auto oact = memzeroed<struct sigaction>();
323	    if (sigaction(SIGINT, &sa, &oact) == -1)
324	      perror("sigaction");
325	
326	    const auto restore_sigint = std::experimental::scope_exit{[&] {
327	      if (sigaction(SIGINT, &oact, nullptr) == -1)
328	        perror("sigaction");
329	    }};
330	
331	    // wait for debugger connections
332	    while (dtm_debug && !dtm.is_connected()) {
333	      dtm.try_accept_socket();
334	      if (ctrlc != 0) {
335	        return 130;
336	      }
337	      sleep(1);
338	    }
339	
340	    [[maybe_unused]]
341	    bool ctx_resuming = context_config.continue_from;
342	    [[maybe_unused]]
343	    bool ctx_triggered = false;
344	
345	    for (auto n = uint64_t{0}; n < max_cycles; ++n) {
346	
347	      if (ctx_resuming) [[unlikely]] {
348	        // Pull up PLIC interrupt signal at the first cycle of the resume
349	        platform.int_trigger.write(1);
350	        ctx_resuming = false;
351	        ctx_triggered = true;
352	      }
353	
354	      sc_core::sc_start(platform.clk.period());
355	
356	      trace_.on_cycle(cpu);
357	
358	      if (hybrid_handoff_) [[unlikely]] {
