412	  auto check_hybrid_handoff() -> std::optional<int>
413	  {
414	    if constexpr (!requires { cpu.get_committed_pc(); }) {
415	      return std::nullopt;
416	    } else {
417	      const auto committed = cpu.get_committed_pc();
