18	constexpr auto access_register_command(uint16_t regno, AarSize size, bool write,
19	                                       bool postexec = false) -> uint32_t
20	{
21	  uint32_t cmd = 0;
22	  cmd |= (uint32_t(size) & 0x7u) << 20;
23	  if (postexec) cmd |= 1u << 18;
24	  cmd |= 1u << 17;
25	  if (write) cmd |= 1u << 16;
26	  cmd |= regno;
27	  return cmd;
28	}
