227	  void set_tck_tms_tdi(const bool tck, const bool tms, const bool tdi)
228	  {
229	    if (tck == this->tck)
230	      return;
231	
232	    this->tck = tck;
233	
234	    if (tck) { // rising edge
235	      if (this->state == jtag_state::shift_ir) {
236	        this->ir = jtag_ir((uint8_t) (uint8_t(this->ir) >> 1)
237	                           | (uint8_t(tdi) << (ir_length - 1)));
238	      } else if (this->state == jtag_state::shift_dr) {
239	        this->dr = (this->dr >> 1) | (uint64_t(tdi) << (dr_length - 1));
240	      }
241	      this->state = jtag_state_transitions[size_t(this->state)][size_t(tms)];
242	    } else { // falling edge
243	      if (this->state == jtag_state::test_logic_reset) {
244	        // spdlog::trace("test_logic_reset");
245	        this->ir = jtag_ir::idcode;
246	      } else if (this->state == jtag_state::run_test_idle) {
247	        // spdlog::debug("run_test_idle");
248	      } else if (this->state == jtag_state::capture_dr) {
249	        if (this->ir == jtag_ir::idcode) {
250	          this->dr = idcode;
251	          this->dr_length = 32;
252	        } else if (this->ir == jtag_ir::bypass) {
253	          this->dr = 0;
254	          this->dr_length = 1;
255	        } else if (this->ir == jtag_ir::dtmcs) {
256	          this->dr = this->dtmcs;
257	          this->dr_length = 32;
258	        } else if (this->ir == jtag_ir::dmi) {
259	          handle_dmi_status();
260	          this->dr = this->dmi;
261	          this->dr_length = 34 + abits;
262	        } else {
263	          spdlog::error("capture_dr: unknown ir: {:#x}", uint8_t(this->ir));
264	          return;
265	        }
266	        spdlog::trace("capture_dr: {:#x}", uint64_t(this->dr));
267	      } else if (this->state == jtag_state::shift_ir) {
268	        this->tdo = (uint8_t(ir) & 1) == 1;
269	      } else if (this->state == jtag_state::shift_dr) {
270	        this->tdo = (dr & 1) == 1;
271	      } else if (this->state == jtag_state::update_ir) {
272	        // spdlog::trace("update_ir: {:#x}", uint8_t(this->ir));
273	      } else if (this->state == jtag_state::update_dr) {
274	        // spdlog::trace("update_dr: {:#x}", uint64_t(this->dr));
275	        if (this->ir == jtag_ir::dtmcs) {
